from turtle import *

shape("turtle")
speed(7)

def maak_vierkant20():
  for i in range(4):
    forward(20)
    left(90)

def maak_vierkant50():
  for i in range(4):
    forward(50)
    left(90)

def maak_vierkant100():
  for i in range(4):
    forward(100)
    left(90)

maak_vierkant20()
forward(30)
maak_vierkant50()
forward(60)
maak_vierkant100()
